mapper.select:
select c.id as coupon_id,uc.id as id,uc.id as user_coupon_id,c.name,c.type,c.discount_amount,c.minimum_amount, case when uc.status=0 and uc.expire_time<=now() then 2 else uc.status end as status, c.description,c.valid_from,c.valid_until,uc.receive_time,uc.use_time,uc.order_id,uc.expire_time from user_coupon uc inner join coupon c on c.id=uc.coupon_id where uc.user_id=#{userId}
and uc.status=0 and uc.expire_time<=now() and uc.status=0 and uc.expire_time>now() and uc.status=#{status}
order by uc.receive_time desc
